queries.sql:
SELECT p.Podcast_Name, d.Day, d.Month, y.year
FROM Podcast p
JOIN Debut_Day d ON p.Debut_Day_ID = d.ID JOIN Debut_Year y ON p.Debut_year_ID = y.ID;

SELECT p.Podcast_Name, d.year
FROM Podcast p
JOIN Debut_Year d ON p.Debut_year_ID = d.ID;

SELECT p.Podcast_Name, d.Day, d.Month
FROM Podcast p
JOIN Debut_Day d ON p.Debut_Day_ID = d.ID;

