PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?podcast_name ?day ?month ?year WHERE {
  ?p a :Podcast .
  ?d a :Debut_Date .
  ?p p:hasDebut_Day ?d .
  ?y a :Debut_Year .
  ?p p:hasDebut_Year ?y .
  ?p p:podcast_name ?podcast_name .
  ?d p:day ?day .
  ?d p:month ?month .
  ?y p:year ?year .
} }
  component: { SELECT ?podcast_name ?year WHERE {
  ?p a :Podcast .
  ?d a :Debut_Year .
  ?p p:hasDebut_Year ?d .
  ?p p:podcast_name ?podcast_name .
  ?d p:year ?year .
} }
  component_2: { SELECT ?podcast_name ?day ?month WHERE {
  ?p a :Podcast .
  ?d a :Debut_Date .
  ?p p:hasDebut_Day ?d .
  ?p p:podcast_name ?podcast_name .
  ?d p:day ?day .
  ?d p:month ?month .
} }
}
